import { CancellationToken } from '../../../../base/common/cancellation.js';
import { ITextModel } from '../../../common/model.js';
import { FoldingRegions } from './foldingRanges.js';
import { FoldingLimitReporter, RangeProvider } from './folding.js';

const ID_NAMED_PROVIDER = 'named';

const REGION_START_PATTERN = /^\s*\/\/\s*#region\s*(.*?)\s*$/;
const REGION_END_PATTERN = /^\s*\/\/\s*#endregion\b/;

export interface NamedRegion {
	name: string;
	startLineNumber: number;
	endLineNumber: number;
}

/**
 * Computes named folding regions from `// #region <name>` / `// #endregion` markers.
 * Returns both the FoldingRegions (for folding) and a list of NamedRegion entries.
 */
export function computeNamedRegions(model: ITextModel, foldingRangesLimit: FoldingLimitReporter): { regions: FoldingRegions; named: NamedRegion[] } {
	const lineCount = model.getLineCount();

	interface PendingRegion {
		name: string;
		startLineNumber: number;
	}

	const stack: PendingRegion[] = [];
	const completed: Array<{ name: string; startLineNumber: number; endLineNumber: number }> = [];

	for (let lineNumber = 1; lineNumber <= lineCount; lineNumber++) {
		const lineContent = model.getLineContent(lineNumber);

		const startMatch = lineContent.match(REGION_START_PATTERN);
		if (startMatch) {
			stack.push({ name: startMatch[1] || '', startLineNumber: lineNumber });
			continue;
		}

		const endMatch = lineContent.match(REGION_END_PATTERN);
		if (endMatch && stack.length > 0) {
			const pending = stack.pop()!;
			completed.push({
				name: pending.name,
				startLineNumber: pending.startLineNumber,
				endLineNumber: lineNumber,
			});
		}
	}

	// Sort completed regions by start line (ascending)
	completed.sort((a, b) => a.startLineNumber - b.startLineNumber);

	const limit = foldingRangesLimit.limit;
	const count = Math.min(completed.length, limit);
	foldingRangesLimit.update(completed.length, completed.length > limit ? limit : false);

	const startIndexes = new Uint32Array(count);
	const endIndexes = new Uint32Array(count);
	const named: NamedRegion[] = [];

	for (let i = 0; i < count; i++) {
		startIndexes[i] = completed[i].startLineNumber;
		endIndexes[i] = completed[i].endLineNumber;
		named.push({
			name: completed[i].name,
			startLineNumber: completed[i].startLineNumber,
			endLineNumber: completed[i].endLineNumber,
		});
	}

	return {
		regions: new FoldingRegions(startIndexes, endIndexes),
		named,
	};
}

export class NamedFoldingRangeProvider implements RangeProvider {
	readonly id = ID_NAMED_PROVIDER;

	private _namedRegions: NamedRegion[] = [];

	constructor(
		private readonly editorModel: ITextModel,
		private readonly foldingRangesLimit: FoldingLimitReporter,
	) { }

	dispose() { }

	compute(_cancellationToken: CancellationToken): Promise<FoldingRegions | null> {
		const result = computeNamedRegions(this.editorModel, this.foldingRangesLimit);
		this._namedRegions = result.named;
		return Promise.resolve(result.regions);
	}

	getNamedRegions(): NamedRegion[] {
		return this._namedRegions;
	}
}

