    37→// public only for testing
    38→export class RangesCollector {
    39→	private readonly _startIndexes: number[];
    40→	private readonly _endIndexes: number[];
    41→	private readonly _indentOccurrences: number[];
    42→	private _length: number;
    43→	private readonly _foldingRangesLimit: FoldingLimitReporter;
    44→
    45→	constructor(foldingRangesLimit: FoldingLimitReporter) {
    46→		this._startIndexes = [];
    47→		this._endIndexes = [];
    48→		this._indentOccurrences = [];
    49→		this._length = 0;
    50→		this._foldingRangesLimit = foldingRangesLimit;
    51→	}
    52→
    53→	public insertFirst(startLineNumber: number, endLineNumber: number, indent: number) {
    54→		if (startLineNumber > MAX_LINE_NUMBER || endLineNumber > MAX_LINE_NUMBER) {
    55→			return;
    56→		}
    57→		const index = this._length;
    58→		this._startIndexes[index] = startLineNumber;
    59→		this._endIndexes[index] = endLineNumber;
    60→		this._length++;
    61→		if (indent < 1000) {
    62→			this._indentOccurrences[indent] = (this._indentOccurrences[indent] || 0) + 1;
    63→		}
    64→	}
    65→
    66→	public toIndentRanges(model: ITextModel) {
    67→		const limit = this._foldingRangesLimit.limit;
    68→		if (this._length <= limit) {
    69→			this._foldingRangesLimit.update(this._length, false);
    70→
    71→			// reverse and create arrays of the exact length
    72→			const startIndexes = new Uint32Array(this._length);
    73→			const endIndexes = new Uint32Array(this._length);
    74→			for (let i = this._length - 1, k = 0; i >= 0; i--, k++) {
    75→				startIndexes[k] = this._startIndexes[i];
    76→				endIndexes[k] = this._endIndexes[i];
    77→			}
