import { KeyCode, KeyMod } from '../../../../base/common/keyCodes.js';
import { ICodeEditor } from '../../../browser/editorBrowser.js';
import { EditorAction, registerEditorAction, ServicesAccessor } from '../../../browser/editorExtensions.js';
import { ScrollType } from '../../../common/editorCommon.js';
import { EditorContextKeys } from '../../../common/editorContextKeys.js';
import * as nls from '../../../../nls.js';
import { KeybindingWeight } from '../../../../platform/keybinding/common/keybindingsRegistry.js';
import { IQuickInputService, IQuickPickItem } from '../../../../platform/quickinput/common/quickInput.js';
import { computeNamedRegions, NamedRegion } from './namedFoldingRangeProvider.js';
import { FoldingController } from './folding.js';
import { setCollapseStateForMatchingLines } from './foldingModel.js';

const MAX_NAMED_REGIONS = 5000;

interface NamedRegionPickItem extends IQuickPickItem {
	region: NamedRegion;
}

class GoToNamedRegionAction extends EditorAction {
	constructor() {
		super({
			id: 'editor.action.goToNamedRegion',
			label: nls.localize2('goToNamedRegion.label', "Go to Named Region"),
			precondition: EditorContextKeys.hasNonEmptySelection.toNegated(),
			kbOpts: {
				kbExpr: EditorContextKeys.editorTextFocus,
				primary: KeyMod.CtrlCmd | KeyMod.Shift | KeyCode.KeyR,
				weight: KeybindingWeight.EditorContrib,
			},
		});
	}

	async run(accessor: ServicesAccessor, editor: ICodeEditor): Promise<void> {
		const quickInputService = accessor.get(IQuickInputService);
		const model = editor.getModel();
		if (!model) {
			return;
		}

		const limitReporter = { limit: MAX_NAMED_REGIONS, update: () => { } };
		const { named } = computeNamedRegions(model, limitReporter);

		if (named.length === 0) {
			return;
		}

		const picks: NamedRegionPickItem[] = named.map(region => ({
			label: region.name || nls.localize('unnamedRegion', "(unnamed region)"),
			description: nls.localize('regionLine', "Line {0}", region.startLineNumber),
			region,
		}));

		const picked = await quickInputService.pick(picks, {
			placeHolder: nls.localize('goToNamedRegion.placeholder', "Select a named region to navigate to"),
			canPickMany: false,
		});

		if (!picked) {
			return;
		}

		const { startLineNumber } = picked.region;

		// Unfold the region if it is collapsed
		const foldingController = FoldingController.get(editor);
		if (foldingController) {
			const foldingModelPromise = foldingController.getFoldingModel();
			if (foldingModelPromise) {
				const foldingModel = await foldingModelPromise;
				if (foldingModel) {
					// Unfold the specific region that starts at startLineNumber
					setCollapseStateForMatchingLines(foldingModel, new RegExp(''), false);
					const regions = foldingModel.regions;
					const toUnfold = [];
					for (let i = 0; i < regions.length; i++) {
						if (regions.getStartLineNumber(i) === startLineNumber && regions.isCollapsed(i)) {
							toUnfold.push(regions.toRegion(i));
						}
					}
					if (toUnfold.length > 0) {
						foldingModel.toggleCollapseState(toUnfold);
						foldingController.triggerFoldingModelChanged();
					}
				}
			}
		}

		editor.setPosition({ lineNumber: startLineNumber, column: 1 });
		editor.revealPositionInCenterIfOutsideViewport({ lineNumber: startLineNumber, column: 1 }, ScrollType.Smooth);
	}
}

registerEditorAction(GoToNamedRegionAction);

