import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { computeNamedRegions, NamedRegion } from '../../browser/namedFoldingRangeProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';
import { FoldingLimitReporter } from '../../browser/folding.js';

const unlimitedReporter: FoldingLimitReporter = {
	limit: 5000,
	update: () => { },
};

function assertNamedRegions(lines: string[], expected: NamedRegion[]): void {
	const model = createTextModel(lines.join('\n'));
	const { named } = computeNamedRegions(model, unlimitedReporter);
	assert.deepStrictEqual(named, expected);
