suite('Named Folding Range Provider', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('detects a single named region', () => {
		assertNamedRegions([
			/* 1 */ '// #region MySection',
			/* 2 */ 'const x = 1;',
			/* 3 */ '// #endregion',
		], [
			{ name: 'MySection', startLineNumber: 1, endLineNumber: 3 },
		]);
	});

	test('detects multiple named regions', () => {
		assertNamedRegions([
			/* 1 */ '// #region Alpha',
			/* 2 */ 'const a = 1;',
			/* 3 */ '// #endregion',
			/* 4 */ '// #region Beta',
			/* 5 */ 'const b = 2;',
			/* 6 */ '// #endregion',
		], [
			{ name: 'Alpha', startLineNumber: 1, endLineNumber: 3 },
			{ name: 'Beta', startLineNumber: 4, endLineNumber: 6 },
		]);
	});

	test('detects nested named regions', () => {
		assertNamedRegions([
			/* 1 */ '// #region Outer',
			/* 2 */ '  // #region Inner',
			/* 3 */ '  const x = 1;',
			/* 4 */ '  // #endregion',
			/* 5 */ '// #endregion',
		], [
			{ name: 'Inner', startLineNumber: 2, endLineNumber: 4 },
			{ name: 'Outer', startLineNumber: 1, endLineNumber: 5 },
		]);
	});

	test('handles unnamed region (no name after #region)', () => {
		assertNamedRegions([
			/* 1 */ '// #region',
			/* 2 */ 'const x = 1;',
			/* 3 */ '// #endregion',
		], [
			{ name: '', startLineNumber: 1, endLineNumber: 3 },
		]);
	});

	test('ignores unmatched #endregion', () => {
		assertNamedRegions([
			/* 1 */ '// #endregion',
			/* 2 */ 'const x = 1;',
		], []);
	});

	test('ignores unclosed #region (no matching #endregion)', () => {
		assertNamedRegions([
			/* 1 */ '// #region Unclosed',
			/* 2 */ 'const x = 1;',
		], []);
	});

	test('extracts the correct folding region line numbers', () => {
		const lines = [
			/* 1 */ '// #region Section1',
			/* 2 */ 'const a = 1;',
			/* 3 */ 'const b = 2;',
			/* 4 */ '// #endregion',
		];
		const model = createTextModel(lines.join('\n'));
		const { regions, named } = computeNamedRegions(model, unlimitedReporter);

		assert.strictEqual(named.length, 1);
		assert.strictEqual(named[0].name, 'Section1');
		assert.strictEqual(named[0].startLineNumber, 1);
		assert.strictEqual(named[0].endLineNumber, 4);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions.getStartLineNumber(0), 1);
		assert.strictEqual(regions.getEndLineNumber(0), 4);

		model.dispose();
	});

	test('respects folding regions limit', () => {
		const lines: string[] = [];
		const expected: NamedRegion[] = [];
		for (let i = 1; i <= 10; i++) {
			lines.push(`// #region Region${i}`);
			lines.push(`const x${i} = ${i};`);
			lines.push('// #endregion');
		}

		let updatedComputed = 0;
		let updatedLimit: number | false = false;
		const limitedReporter: FoldingLimitReporter = {
			limit: 3,
			update(computed, limited) {
				updatedComputed = computed;
				updatedLimit = limited;
			},
		};

		const model = createTextModel(lines.join('\n'));
		const { regions } = computeNamedRegions(model, limitedReporter);

		assert.strictEqual(regions.length, 3);
		assert.strictEqual(updatedComputed, 10);
		assert.strictEqual(updatedLimit, 3);

		model.dispose();
	});

	test('handles leading whitespace in markers', () => {
		assertNamedRegions([
			/* 1 */ '    // #region Indented',
			/* 2 */ '    const x = 1;',
			/* 3 */ '    // #endregion',
		], [
			{ name: 'Indented', startLineNumber: 1, endLineNumber: 3 },
		]);
	});

	test('trims trailing whitespace from region name', () => {
		assertNamedRegions([
			/* 1 */ '// #region   TrimMe   ',
			/* 2 */ 'const x = 1;',
			/* 3 */ '// #endregion',
		], [
			{ name: 'TrimMe', startLineNumber: 1, endLineNumber: 3 },
		]);
	});

	test('empty file produces no regions', () => {
		assertNamedRegions([], []);
	});
});
